import React from 'react';
import './PostSection.css';
import Post from '../Posts/Post';

const PostsSection = () => {
  const posts = [
    {
      image: 'https://img.freepik.com/vector-gratis/dibujado-mano-mujer-embarazada-dibujo-ilustracion_23-2150452532.jpg',
      title: 'Title Post 1',
      date: 'Date Post 1',
      description: 'Description Post 1...'
    },
    {
      image: 'https://img.freepik.com/vector-gratis/dibujado-mano-mujer-embarazada-dibujo-ilustracion_23-2150452532.jpg',
      title: 'Title Post 2',
      date: 'Date Post 2',
      description: 'Description Post 2...'
    },
    {
      image: 'https://assets1.farmaciasanpablo.com.mx/landings/_blog/bebes/230125-10cuidadosEmbarazada/10-cuidados-que-debe-tener-una-mujer-embarazada.jpg',
      title: 'Title Post 3',
      date: 'Date Post 3',
      description: 'Description Post 3...'
    },
    {
      image: 'url-to-image-4.jpg',
      title: 'Title Post 4',
      date: 'Date Post 4',
      description: 'Description Post 4...'
    }
  ];

  return (
    <section id="posts" className="posts-section">
      <h2>פוסטים</h2>
      <div className="posts-container">
        {posts.map((post, index) => (
          <Post
            key={index}
            image={post.image}
            title={post.title}
            date={post.date}
            description={post.description}
          />
        ))}
      </div>
    </section>
  );
};

export default PostsSection;
